package client.cli.org.apache.syncope.client.cli.commands.configuration;

@ Command ( name = "configuration" ) public class ConfigurationCommand extends AbstractCommand { private final ConfigurationResultManager configurationResultManager = new ConfigurationResultManager ( ) ; @ Override public void execute ( final Input input ) { if ( StringUtils . isBlank ( input . getOption ( ) ) ) { input . setOption ( Options . HELP . getOptionName ( ) ) ; } switch ( Options . fromName ( input . getOption ( ) ) ) { case GET : new ConfigurationGet ( input ) . get ( ) ; break ; case READ : new ConfigurationRead ( input ) . read ( ) ; break ; case UPDATE : new ConfigurationUpdate ( input ) . update ( ) ; break ; case DELETE : new ConfigurationDelete ( input ) . delete ( ) ; break ; case EXPORT : new ConfigurationExport ( input ) . export ( ) ; break ; case HELP : System . out . println ( getHelpMessage ( ) ) ; break ; default : configurationResultManager . defaultOptionMessage ( input . getOption ( ) , getHelpMessage ( ) ) ; } } @ Override public String getHelpMessage ( ) { return configurationResultManager . commandHelpMessage ( getClass ( ) ) ; } private enum Options { HELP ( "--help" ) , GET ( "--get" ) , READ ( "--read" ) , UPDATE ( "--update" ) , DELETE ( "--delete" ) , EXPORT ( "--export" ) ; private final String optionName ; Options ( final String optionName ) { this . optionName = optionName ; } public String getOptionName ( ) { return optionName ; } public boolean equalsOptionName ( final String otherName ) { return ( otherName == null ) ? false : optionName . equals ( otherName ) ; } public static Options fromName ( final String name ) { Options optionToReturn = HELP ; for ( final Options option : Options . values ( ) ) { if ( option . equalsOptionName ( name ) ) { optionToReturn = option ; } } return optionToReturn ; } public static List < String > toList ( ) { final List < String > options = new ArrayList < > ( ) ; for ( final Options value : values ( ) ) { options . add ( value . getOptionName ( ) ) ; } return options ; } } }